      options: [{ id: `A`, text: `ŌĆ£Report on the Barnhouse Effect,ŌĆØ a short story, was Kurt Vonnegut's first published work of fiction.` }, { id: `B`, text: `Acclaimed writer Kurt Vonnegut's first published work of fiction appeared in <i>Collier's</i>.` }, { id: `C`, text: `The publication of ŌĆ£Report on the Barnhouse EffectŌĆØ introduced Kurt Vonnegut's work to a wider audience.` }, { id: `D`, text: `Kurt Vonnegut's short story ŌĆ£Report on the Barnhouse EffectŌĆØ was published in 1950.` }],
